parameters.content:
/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for email delivery.
 * Provides template rendering, recipient resolution, and structured
 * email composition with both HTML and plain text output.
 *
 * ## Features
 *
 * - **Template rendering**: Generates HTML emails from named templates
 *   with dynamic content. Select a template via `metadata.template`
 *   in the NotificationPayload, or let the adapter auto-detect based
 *   on the subject line.
 * - **Recipient resolution**: Validates email addresses and supports
 *   `"Display Name <email>"` format, extracting address and name.
 * - **Priority-aware delivery**: Renders a priority banner in the
 *   HTML output for `high` and `urgent` notifications.
 *
 * ## Usage
 *
 * ```typescript
 * const emailAdapter = new EmailAdapter();
 * notificationService.registerAdapter(emailAdapter);
 * ```
 *
 * ## Templates
 *
 * Built-in templates:
 * - `order-confirmation` — Order confirmation with item summary
 * - `order-status-update` — Order status change notification
 * - `welcome` — New user welcome email
 * - `default` — Generic notification wrapper
 *
 * Select a template explicitly via `metadata.template`:
 * ```typescript
 * await service.dispatchNotification({
 *   type: 'email',
 *   recipient: 'alice@example.com',
 *   subject: 'Welcome!',
 *   body: 'Welcome to TaskFlow Pro.',
 *   metadata: { template: 'welcome', recipientName: 'Alice' },
 * });
 * ```
 *
 * ## Replacing with a real provider
 *
 * To use a real email provider (SendGrid, SES, Mailgun), modify the
 * `send()` method to call the provider API after template rendering.
 * Wrap external API errors and return `{ success: false, error: '...' }`.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Supported email template names.
 * Templates determine the HTML structure and styling of the email.
 */
export type EmailTemplateName =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'default';

/** All valid template names for runtime validation. */
const VALID_TEMPLATES: readonly EmailTemplateName[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'default',
];

/**
 * Rendered email content with both HTML and plain text versions.
 */
export interface RenderedEmail {
  /** Full HTML email content with inline styles. */
  html: string;
  /** Plain text fallback for clients that don't support HTML. */
  text: string;
}

/**
 * Resolved recipient with optional display name.
 */
export interface ResolvedRecipient {
  /** The validated email address. */
  email: string;
  /** Display name parsed from `"Name <email>"` format. */
  name?: string;
}

/**
 * An email message as stored by the adapter.
 * Includes both the original content and the rendered output.
 * Useful for testing and asserting on sent emails.
 */
export interface SentEmail {
  /** Unique message identifier (e.g., `email-0001`). */
  messageId: string;

  /** Recipient email address. */
  to: string;

  /** Recipient display name, if resolved from the recipient string. */
  toName?: string;

  /** Email subject line. */
  subject: string;

  /** Original plain text body content. */
  body: string;

  /** Rendered HTML email content. */
  html: string;

  /** Notification priority level. */
  priority: NotificationPriority;

  /** Template used for rendering. */
  template: EmailTemplateName;

  /** When the email was "sent" (recorded). */
  sentAt: Date;
}

/** Simple email format validation. */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/** `"Display Name <email>"` format. */
const NAMED_EMAIL_REGEX = /^(.+?)\s*<([^\s@]+@[^\s@]+\.[^\s@]+)>$/;

let nextMessageId = 1;

function generateMessageId(): string {
  return `email-${String(nextMessageId++).padStart(4, '0')}`;
}

/**
 * Reset the message ID counter. For testing only.
 */
export function resetEmailMessageIdCounter(): void {
  nextMessageId = 1;
}

/**
 * Escape HTML special characters to prevent injection in rendered templates.
 */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailAdapter implements NotificationAdapter {
  readonly type: NotificationType = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Resolve and validate an email recipient string.
   *
   * Supports two formats:
   * - Plain email: `"alice@example.com"`
   * - Named email: `"Alice Smith <alice@example.com>"`
   *
   * @param recipient - The recipient string to resolve.
   * @returns The resolved recipient, or `null` if the format is invalid.
   */
  resolveRecipient(recipient: string): ResolvedRecipient | null {
    const trimmed = recipient.trim();

    // Try "Display Name <email>" format first
    const namedMatch = NAMED_EMAIL_REGEX.exec(trimmed);
    if (namedMatch) {
      return {
        email: namedMatch[2]!,
        name: namedMatch[1]!.trim(),
      };
    }

    // Try plain email format
    if (EMAIL_REGEX.test(trimmed)) {
      return { email: trimmed };
    }

    return null;
  }

  /**
   * Select the appropriate email template for a notification payload.
   *
   * Template selection priority:
   * 1. Explicit `metadata.template` value (if it's a valid template name)
   * 2. Auto-detection from subject line patterns
   * 3. Falls back to `'default'`
   *
   * @param payload - The notification payload.
   * @returns The template name to use for rendering.
   */
  selectTemplate(payload: NotificationPayload): EmailTemplateName {
    // 1. Check explicit metadata.template
    if (payload.metadata?.template) {
      const requested = payload.metadata.template as string;
      if (VALID_TEMPLATES.includes(requested as EmailTemplateName)) {
        return requested as EmailTemplateName;
      }
    }

    // 2. Auto-detect from subject patterns
    const subject = payload.subject.toLowerCase();
    if (subject.includes('order confirmation')) {
      return 'order-confirmation';
    }
    if (subject.includes('order update') || subject.includes('status')) {
      return 'order-status-update';
    }
    if (subject.includes('welcome')) {
      return 'welcome';
    }

    // 3. Default
    return 'default';
  }

  /**
   * Render an email template with the given data.
   *
   * Produces both HTML and plain text versions. The HTML output uses
   * inline styles for maximum email client compatibility.
   *
   * @param template - The template name to render.
   * @param data - Content and metadata for the template.
   * @returns The rendered email with HTML and plain text content.
   */
  renderTemplate(
    template: EmailTemplateName,
    data: {
      subject: string;
      body: string;
      recipientName?: string;
      priority: NotificationPriority;
    },
  ): RenderedEmail {
    const escapedSubject = escapeHtml(data.subject);
    const escapedBody = escapeHtml(data.body);
    const greeting = data.recipientName
      ? `<p>Dear ${escapeHtml(data.recipientName)},</p>`
      : '';

    const priorityBanner =
      data.priority === 'urgent' || data.priority === 'high'
        ? `<div style="background-color: #fed7d7; color: #9b2c2c; padding: 8px 16px; border-radius: 4px; margin-bottom: 16px; font-weight: bold;">Priority: ${escapeHtml(data.priority.toUpperCase())}</div>`
        : '';

    const footer =
      '<p style="color: #718096; font-size: 12px; margin-top: 24px; border-top: 1px solid #e2e8f0; padding-top: 12px;">This is an automated message from TaskFlow Pro. Please do not reply directly to this email.</p>';

    const textGreeting = data.recipientName
      ? `Dear ${data.recipientName},\n\n`
      : '';
    const textPriority =
      data.priority === 'urgent' || data.priority === 'high'
        ? `[Priority: ${data.priority.toUpperCase()}]\n\n`
        : '';
    const textFooter =
      '\n\n---\nThis is an automated message from TaskFlow Pro. Please do not reply directly to this email.';

    let html: string;
    let text: string;

    switch (template) {
      case 'order-confirmation':
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">${priorityBanner}<h1 style="color: #2d3748; border-bottom: 2px solid #4299e1; padding-bottom: 8px;">Order Confirmation</h1>${greeting}<p>${escapedBody}</p><p style="color: #4a5568; font-style: italic;">Thank you for your order!</p>${footer}</div>`;
        text = `${textPriority}${textGreeting}${data.body}\n\nThank you for your order!${textFooter}`;
        break;

      case 'order-status-update':
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">${priorityBanner}<h1 style="color: #2d3748; border-bottom: 2px solid #ed8936; padding-bottom: 8px;">Order Status Update</h1>${greeting}<p>${escapedBody}</p><p style="color: #4a5568;">You can track your order in your account dashboard.</p>${footer}</div>`;
        text = `${textPriority}${textGreeting}${data.body}\n\nYou can track your order in your account dashboard.${textFooter}`;
        break;

      case 'welcome':
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">${priorityBanner}<h1 style="color: #2d3748; border-bottom: 2px solid #48bb78; padding-bottom: 8px;">Welcome to TaskFlow Pro!</h1>${greeting}<p>${escapedBody}</p><p style="color: #4a5568;">We're glad to have you on board. Get started by exploring your dashboard.</p>${footer}</div>`;
        text = `${textPriority}${textGreeting}${data.body}\n\nWe're glad to have you on board. Get started by exploring your dashboard.${textFooter}`;
        break;

      default:
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">${priorityBanner}<h1 style="color: #2d3748;">${escapedSubject}</h1>${greeting}<p>${escapedBody}</p>${footer}</div>`;
        text = `${textPriority}${textGreeting}${data.body}${textFooter}`;
        break;
    }

    return { html, text };
  }

  /**
   * Send an email notification.
   *
   * Performs recipient resolution, template selection, and template
   * rendering, then stores the composed email. Returns a failure result
   * if the recipient is not a valid email address.
   *
   * @param payload - The notification payload to deliver via email.
   * @returns A result indicating delivery success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const timestamp = new Date();

    try {
      // 1. Resolve and validate recipient
      const resolved = this.resolveRecipient(payload.recipient);
      if (!resolved) {
        this.logger.error(`Invalid recipient email address: ${payload.recipient}`);
        return {
          success: false,
          error: `Invalid recipient email address: ${payload.recipient}`,
          timestamp,
        };
      }

      // 2. Select template
      const template = this.selectTemplate(payload);

      // 3. Render template
      const recipientName =
        (payload.metadata?.recipientName as string | undefined) ?? resolved.name;
      const rendered = this.renderTemplate(template, {
        subject: payload.subject,
        body: payload.body,
        recipientName,
        priority: payload.priority ?? 'normal',
      });

      // 4. Generate ID and store composed email
      const messageId = generateMessageId();

      const email: SentEmail = {
        messageId,
        to: resolved.email,
        toName: recipientName,
        subject: payload.subject,
        body: payload.body,
        html: rendered.html,
        priority: payload.priority ?? 'normal',
        template,
        sentAt: timestamp,
      };

      this.sentEmails.push(email);
      this.logger.info(
        `Email sent: ${messageId} to ${resolved.email} [${template}] — "${payload.subject}"`,
      );

      return {
        success: true,
        messageId,
        timestamp,
      };
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Unknown email delivery error';
      this.logger.error(
        `Email delivery failed for ${payload.recipient}: ${errorMessage}`,
      );

      return {
        success: false,
        error: errorMessage,
        timestamp,
      };
    }
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails sent to a specific recipient. Useful for testing.
   */
  getSentEmailsTo(recipient: string): SentEmail[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

