import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  resetEmailMessageIdCounter,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailTemplateName,
  ResolvedRecipient,
  SentEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
    resetEmailMessageIdCounter();
  });

  describe('type', () => {
    it('should have type "email"', () => {
      expect(adapter.type).toBe('email');
    });
  });

  // ---------------------------------------------------------------------------
  // resolveRecipient
  // ---------------------------------------------------------------------------
  describe('resolveRecipient', () => {
    it('should resolve a plain email address', () => {
      const result = adapter.resolveRecipient('alice@example.com');
      expect(result).toEqual({ email: 'alice@example.com' });
    });

    it('should resolve "Display Name <email>" format', () => {
      const result = adapter.resolveRecipient('Alice Smith <alice@example.com>');
      expect(result).toEqual({ email: 'alice@example.com', name: 'Alice Smith' });
    });

    it('should handle extra whitespace in named format', () => {
      const result = adapter.resolveRecipient('  Bob Jones   <bob@test.org>  ');
      expect(result).toEqual({ email: 'bob@test.org', name: 'Bob Jones' });
    });

    it('should return null for an invalid email', () => {
      expect(adapter.resolveRecipient('not-an-email')).toBeNull();
    });

    it('should return null for an empty string', () => {
      expect(adapter.resolveRecipient('')).toBeNull();
    });

    it('should return null for a string with only whitespace', () => {
      expect(adapter.resolveRecipient('   ')).toBeNull();
    });

    it('should return null for a user ID (no @ sign)', () => {
      expect(adapter.resolveRecipient('user-123')).toBeNull();
    });

    it('should resolve email with subdomain', () => {
      const result = adapter.resolveRecipient('admin@mail.company.co.uk');
      expect(result).toEqual({ email: 'admin@mail.company.co.uk' });
    });
  });

  // ---------------------------------------------------------------------------
  // selectTemplate
  // ---------------------------------------------------------------------------
  describe('selectTemplate', () => {
    it('should select "order-confirmation" from subject', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Order Confirmation: ORD-001',
        body: 'Your order has been placed.',
      };
      expect(adapter.selectTemplate(payload)).toBe('order-confirmation');
    });

    it('should select "order-status-update" from subject containing "Order Update"', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Order Update: ORD-001',
        body: 'Your order status has changed.',
      };
      expect(adapter.selectTemplate(payload)).toBe('order-status-update');
    });

    it('should select "order-status-update" from subject containing "status"', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Your delivery status changed',
        body: 'Updated.',
      };
      expect(adapter.selectTemplate(payload)).toBe('order-status-update');
    });

    it('should select "welcome" from subject', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hello.',
      };
      expect(adapter.selectTemplate(payload)).toBe('welcome');
    });

    it('should fall back to "default" for unknown subjects', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Monthly Newsletter',
        body: 'News.',
      };
      expect(adapter.selectTemplate(payload)).toBe('default');
    });

    it('should use explicit metadata.template over subject detection', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Order Confirmation: ORD-001',
        body: 'Body.',
        metadata: { template: 'welcome' },
      };
      expect(adapter.selectTemplate(payload)).toBe('welcome');
    });

    it('should ignore invalid metadata.template and fall back to auto-detect', () => {
      const payload: NotificationPayload = {
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Order Confirmation: ORD-001',
        body: 'Body.',
        metadata: { template: 'nonexistent-template' },
      };
      // Falls through to subject-based detection
      expect(adapter.selectTemplate(payload)).toBe('order-confirmation');
    });
  });

  // ---------------------------------------------------------------------------
  // renderTemplate
  // ---------------------------------------------------------------------------
  describe('renderTemplate', () => {
    it('should render order-confirmation template with greeting', () => {
      const rendered = adapter.renderTemplate('order-confirmation', {
        subject: 'Order Confirmation: ORD-001',
        body: 'Items: Widget x2. Total: $20.00',
        recipientName: 'Alice',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Order Confirmation');
      expect(rendered.html).toContain('Dear Alice');
      expect(rendered.html).toContain('Items: Widget x2. Total: $20.00');
      expect(rendered.html).toContain('Thank you for your order!');
      expect(rendered.html).toContain('TaskFlow Pro');
      expect(rendered.text).toContain('Dear Alice');
      expect(rendered.text).toContain('Items: Widget x2. Total: $20.00');
      expect(rendered.text).toContain('Thank you for your order!');
    });

    it('should render order-status-update template', () => {
      const rendered = adapter.renderTemplate('order-status-update', {
        subject: 'Order Update: ORD-001',
        body: 'Status changed from pending to confirmed.',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.html).toContain('Status changed from pending to confirmed.');
      expect(rendered.html).toContain('track your order');
      expect(rendered.text).toContain('Status changed from pending to confirmed.');
      expect(rendered.text).toContain('track your order');
    });

    it('should render welcome template', () => {
      const rendered = adapter.renderTemplate('welcome', {
        subject: 'Welcome!',
        body: 'Welcome to the platform.',
        recipientName: 'Bob',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Welcome to TaskFlow Pro!');
      expect(rendered.html).toContain('Dear Bob');
      expect(rendered.html).toContain('glad to have you on board');
      expect(rendered.text).toContain('Dear Bob');
      expect(rendered.text).toContain('glad to have you on board');
    });

    it('should render default template with subject as heading', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Monthly Report',
        body: 'Here is your report.',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Monthly Report');
      expect(rendered.html).toContain('Here is your report.');
      expect(rendered.text).toContain('Here is your report.');
    });

    it('should include priority banner for urgent priority', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Alert',
        body: 'Critical issue.',
        priority: 'urgent',
      });

      expect(rendered.html).toContain('Priority: URGENT');
      expect(rendered.text).toContain('[Priority: URGENT]');
    });

    it('should include priority banner for high priority', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Alert',
        body: 'Important issue.',
        priority: 'high',
      });

      expect(rendered.html).toContain('Priority: HIGH');
      expect(rendered.text).toContain('[Priority: HIGH]');
    });

    it('should not include priority banner for normal priority', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Info',
        body: 'Just a note.',
        priority: 'normal',
      });

      expect(rendered.html).not.toContain('Priority:');
      expect(rendered.text).not.toContain('[Priority:');
    });

    it('should not include priority banner for low priority', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'FYI',
        body: 'Low priority note.',
        priority: 'low',
      });

      expect(rendered.html).not.toContain('Priority:');
      expect(rendered.text).not.toContain('[Priority:');
    });

    it('should omit greeting when recipientName is not provided', () => {
      const rendered = adapter.renderTemplate('order-confirmation', {
        subject: 'Order Confirmation',
        body: 'Order placed.',
        priority: 'normal',
      });

      expect(rendered.html).not.toContain('Dear');
      expect(rendered.text).not.toContain('Dear');
    });

    it('should escape HTML special characters in body', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Test',
        body: '<script>alert("xss")</script>',
        priority: 'normal',
      });

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
      // Plain text preserves the original content
      expect(rendered.text).toContain('<script>alert("xss")</script>');
    });

    it('should escape HTML special characters in subject', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Test & "Quotes" <Tags>',
        body: 'Body.',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Test &amp; &quot;Quotes&quot; &lt;Tags&gt;');
    });

    it('should escape HTML special characters in recipientName', () => {
      const rendered = adapter.renderTemplate('default', {
        subject: 'Test',
        body: 'Body.',
        recipientName: '<script>Bob</script>',
        priority: 'normal',
      });

      expect(rendered.html).toContain('Dear &lt;script&gt;Bob&lt;/script&gt;');
      expect(rendered.html).not.toContain('Dear <script>');
    });
  });

  // ---------------------------------------------------------------------------
  // send
  // ---------------------------------------------------------------------------
  describe('send', () => {
    it('should send a valid email successfully', async () => {
      const result = await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: ORD-001',
        body: 'Items: Widget x2. Total: $20.00',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(result.messageId).toBe('email-0001');
      expect(result.timestamp).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the sent email with all fields', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: ORD-001',
        body: 'Items: Widget x2. Total: $20.00',
        priority: 'high',
      });

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);

      const email = emails[0]!;
      expect(email.to).toBe('alice@example.com');
      expect(email.subject).toBe('Order Confirmation: ORD-001');
      expect(email.body).toBe('Items: Widget x2. Total: $20.00');
      expect(email.html).toContain('Order Confirmation');
      expect(email.html).toContain('Items: Widget x2. Total: $20.00');
      expect(email.priority).toBe('high');
      expect(email.template).toBe('order-confirmation');
      expect(email.messageId).toBe('email-0001');
      expect(email.sentAt).toBeInstanceOf(Date);
    });

    it('should fail for an invalid recipient email', async () => {
      const result = await adapter.send({
        type: 'email',
        recipient: 'not-a-valid-email',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email address');
      expect(result.error).toContain('not-a-valid-email');
      expect(adapter.getSentEmailCount()).toBe(0);
    });

    it('should fail for an empty recipient', async () => {
      const result = await adapter.send({
        type: 'email',
        recipient: '',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email address');
    });

    it('should resolve "Name <email>" format in send', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'Alice Smith <alice@example.com>',
        subject: 'Hello',
        body: 'Greetings.',
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.to).toBe('alice@example.com');
      expect(emails[0]!.toName).toBe('Alice Smith');
      expect(emails[0]!.html).toContain('Dear Alice Smith');
    });

    it('should use metadata.recipientName over resolved name', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'Alice Smith <alice@example.com>',
        subject: 'Hello',
        body: 'Greetings.',
        metadata: { recipientName: 'Dr. Alice' },
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.toName).toBe('Dr. Alice');
      expect(emails[0]!.html).toContain('Dear Dr. Alice');
    });

    it('should use explicit metadata.template', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Custom Subject',
        body: 'Body.',
        metadata: { template: 'welcome' },
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.template).toBe('welcome');
      expect(emails[0]!.html).toContain('Welcome to TaskFlow Pro!');
    });

    it('should auto-detect template from subject when no metadata', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Update: ORD-001',
        body: 'Status changed.',
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.template).toBe('order-status-update');
    });

    it('should default priority to normal when not specified', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body.',
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.priority).toBe('normal');
    });

    it('should include priority banner in HTML for urgent emails', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Critical Alert',
        body: 'System down.',
        priority: 'urgent',
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.html).toContain('Priority: URGENT');
    });

    it('should generate sequential message IDs', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'First',
        body: '1',
      });
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Second',
        body: '2',
      });
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Third',
        body: '3',
      });

      const emails = adapter.getSentEmails();
      expect(emails[0]!.messageId).toBe('email-0001');
      expect(emails[1]!.messageId).toBe('email-0002');
      expect(emails[2]!.messageId).toBe('email-0003');
    });

    it('should never throw — return failure result on unexpected errors', async () => {
      // We can't easily force an internal error in the adapter without
      // modifying internals, but we verify the contract: send() always
      // returns a NotificationResult, never throws.
      const result = await adapter.send({
        type: 'email',
        recipient: 'valid@example.com',
        subject: 'Test',
        body: 'Body',
      });

      // The call should not throw
      expect(result).toBeDefined();
      expect(typeof result.success).toBe('boolean');
      expect(result.timestamp).toBeInstanceOf(Date);
    });
  });

  // ---------------------------------------------------------------------------
  // Test helper methods
  // ---------------------------------------------------------------------------
  describe('getSentEmails', () => {
    it('should return an empty array initially', () => {
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should return a copy, not the internal array', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Test',
        body: 'Body',
      });

      const emails1 = adapter.getSentEmails();
      const emails2 = adapter.getSentEmails();
      expect(emails1).not.toBe(emails2);
      expect(emails1).toEqual(emails2);
    });
  });

  describe('getSentEmailsTo', () => {
    it('should filter emails by recipient', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'To Alice',
        body: 'Hi Alice.',
      });
      await adapter.send({
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'To Bob',
        body: 'Hi Bob.',
      });
      await adapter.send({
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Another to Alice',
        body: 'Hi again.',
      });

      expect(adapter.getSentEmailsTo('alice@example.com')).toHaveLength(2);
      expect(adapter.getSentEmailsTo('bob@example.com')).toHaveLength(1);
      expect(adapter.getSentEmailsTo('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('getSentEmailCount', () => {
    it('should return 0 initially', () => {
      expect(adapter.getSentEmailCount()).toBe(0);
    });

    it('should count sent emails correctly', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'One',
        body: '1',
      });
      await adapter.send({
        type: 'email',
        recipient: 'c@d.com',
        subject: 'Two',
        body: '2',
      });

      expect(adapter.getSentEmailCount()).toBe(2);
    });

    it('should not count failed sends', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'invalid-email',
        subject: 'Fail',
        body: 'Fail',
      });

      expect(adapter.getSentEmailCount()).toBe(0);
    });
  });

  describe('clearSentEmails', () => {
    it('should clear all sent emails', async () => {
      await adapter.send({
        type: 'email',
        recipient: 'a@b.com',
        subject: 'Test',
        body: 'Body',
      });

      expect(adapter.getSentEmailCount()).toBe(1);

      adapter.clearSentEmails();

      expect(adapter.getSentEmailCount()).toBe(0);
      expect(adapter.getSentEmails()).toEqual([]);
    });
  });

  // ---------------------------------------------------------------------------
  // Integration: full pipeline
  // ---------------------------------------------------------------------------
  describe('full send pipeline', () => {
    it('should compose a complete order confirmation email', async () => {
      const result = await adapter.send({
        type: 'email',
        recipient: 'Alice Johnson <alice@example.com>',
        subject: 'Order Confirmation: ORD-42',
        body: 'Your order has been placed. Items: Widget x2, Gadget x1. Total: $45.00',
        priority: 'normal',
        metadata: { recipientName: 'Alice' },
      });

      expect(result.success).toBe(true);

      const email = adapter.getSentEmails()[0]!;
      expect(email.to).toBe('alice@example.com');
      expect(email.toName).toBe('Alice');
      expect(email.template).toBe('order-confirmation');
      expect(email.priority).toBe('normal');
      expect(email.html).toContain('Order Confirmation');
      expect(email.html).toContain('Dear Alice');
      expect(email.html).toContain('Widget x2, Gadget x1');
      expect(email.html).toContain('$45.00');
      expect(email.html).toContain('Thank you for your order!');
      expect(email.html).not.toContain('Priority:');
      expect(email.body).toBe(
        'Your order has been placed. Items: Widget x2, Gadget x1. Total: $45.00',
      );
    });

    it('should compose a high-priority status update email', async () => {
      const result = await adapter.send({
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'Order Update: ORD-99',
        body: 'Your order status has changed from confirmed to shipped.',
        priority: 'high',
      });

      expect(result.success).toBe(true);

      const email = adapter.getSentEmails()[0]!;
      expect(email.template).toBe('order-status-update');
      expect(email.priority).toBe('high');
      expect(email.html).toContain('Order Status Update');
      expect(email.html).toContain('Priority: HIGH');
      expect(email.html).toContain('confirmed to shipped');
      expect(email.html).toContain('track your order');
    });
  });
});

