+    constructor(userRepository, eventBus) {
+        this.userRepository = userRepository;
+        this.eventBus = eventBus;
+    }
+    /**
+     * Create a new user.
+     */
+    async createUser(input) {
+        this.logger.info(`Creating user: ${input.name}`);
+        // Validate email uniqueness
+        const existing = this.userRepository.findByEmail(input.email);
+        if (existing) {
+            throw new Error(`User with email ${input.email} already exists`);
+        }
+        const now = new Date();
+        const user = {
+            id: generateId(),
+            name: input.name,
+            email: input.email,
+            role: input.role,
+            createdAt: now,
+            updatedAt: now,
+        };
+        this.userRepository.save(user);
+        await this.eventBus.emit({
+            type: 'user:created',
+            user,
+            timestamp: now,
+        });
+        return user;
+    }
+    /**
+     * Get a user by ID.
+     */
+    getUser(id) {
+        return this.userRepository.findById(id);
+    }
+    /**
+     * Update a user.
+     */
+    async updateUser(id, input) {
+        this.logger.info(`Updating user: ${id}`);
+        const existing = this.userRepository.findById(id);
+        if (!existing) {
+            throw new Error(`User not found: ${id}`);
+        }
+        // If changing email, check uniqueness
+        if (input.email && input.email !== existing.email) {
+            const emailTaken = this.userRepository.findByEmail(input.email);
+            if (emailTaken) {
+                throw new Error(`Email ${input.email} is already in use`);
+            }
+        }
+        const changes = [];
+        if (input.name && input.name !== existing.name)
+            changes.push('name');
+        if (input.email && input.email !== existing.email)
+            changes.push('email');
+        if (input.role && input.role !== existing.role)
+            changes.push('role');
+        const updated = this.userRepository.update(id, {
+            ...input,
+            updatedAt: new Date(),
+        });
+        if (changes.length > 0) {
+            await this.eventBus.emit({
+                type: 'user:updated',
+                user: updated,
+                changes,
+                timestamp: new Date(),
+            });
+        }
+        return updated;
+    }
+    /**
+     * List all users, optionally filtered by role.
+     */
+    listUsers(role) {
+        if (role) {
